pub fn fold_b(a: &[R0], cap: usize) -> Vec<R0> {
    let cap = cap.max(1);
    let mut pool: Vec<R0> = a.to_vec();
    let mut accepted: Vec<R0> = Vec::new();

    let mut turn = 0u64;

    while !pool.is_empty() {
        let mut eligible_by_lane: BTreeMap<String, Vec<R0>> = BTreeMap::new();
        let mut not_eligible: Vec<R0> = Vec::new();

        for row in pool.drain(..) {
            if row.base_turn <= turn {
                eligible_by_lane.entry(row.lane_name.clone()).or_default().push(row);
            } else {
                not_eligible.push(row);
            }
        }

        let mut any_accepted = false;
        for (_lane, mut rows) in eligible_by_lane {
            rows.sort_by_key(|r| r.seq);
            let take = rows.len().min(cap);
            for mut row in rows.drain(..take) {
                row.turn = turn;
                accepted.push(row);
                any_accepted = true;
            }
            not_eligible.extend(rows);
        }

        pool = not_eligible;

        if !any_accepted {
            if let Some(next) = pool.iter().map(|r| r.base_turn).min() {
                turn = next;
            } else {
                break;
            }
        } else {
            turn += 1;
        }
    }

    accepted.sort_by(|l, r| l.turn.cmp(&r.turn).then(l.lane_name.cmp(&r.lane_name)).then(l.seq.cmp(&r.seq)));
    accepted
}
